// Decide how many pages to scrape.
// On first run (no seen URLs stored yet), scrape all pages (up to MAX_PAGES).
// On subsequent runs, scrape only page 1 to catch the latest releases.

const store = $getWorkflowStaticData('global');
const seenUrls = store.seenUrls || [];

const isFirstRun = seenUrls.length === 0;
const MAX_PAGES = isFirstRun ? 50 : 1;  // adjust 50 to however deep you want the first scrape

const pages = [];
for (let i = 0; i < MAX_PAGES; i++) {
  pages.push({
    json: {
      page: i,
      offset: i * 15,   // coreradio uses 15 items per page
      isFirstRun: isFirstRun
    }
  });
}

return pages;

const _res = $input.first().json;

// ── Defensive: surface whatever we got if body is missing ─────────────────
const html = _res.body || _res.data || _res.html || _res.text || '';

if (!html) {
  return [{ json: {
    debug: true,
    error: 'No HTML body found',
    availableKeys: Object.keys(_res),
    rawInput: JSON.stringify(_res).slice(0, 500)
  }}];
}

// ── Helpers ───────────────────────────────────────────────────────────────

function parseTitle(raw) {
  raw = raw.replace(/\\/g, '');
  for (const sep of [' - ', ' \u2013 ', ' \u2014 ']) {
    const idx = raw.indexOf(sep);
    if (idx !== -1) {
      const band = raw.slice(0, idx).trim();
      const rest = raw.slice(idx + sep.length).trim();
      const typeMatch = rest.match(/\[([^\]]+)\]/);
      const yearMatch = rest.match(/\((\d{4})\)/);
      const album = rest.replace(/\s*\[[^\]]+\]\s*/, '').replace(/\s*\(\d{4}\)\s*/, '').trim();
      return {
        band,
        album,
        type: typeMatch ? typeMatch[1] : '',
        year: yearMatch ? yearMatch[1] : new Date().getFullYear().toString()
      };
    }
  }
  return { band: raw.trim(), album: 'Unknown', type: '', year: new Date().getFullYear().toString() };
}

function extractMeta(text) {
  const genreMatch   = text.match(/Genre:\s*(.+?)(?:Country:|Quality:|$)/s);
  const countryMatch = text.match(/Country:\s*(.+?)(?:Quality:|$)/s);
  const genres = genreMatch
    ? genreMatch[1].split(/[\/,]/).map(g => g.trim()).filter(Boolean)
    : [];

  return {
    genres,
    genre:   genres.join(', ') || 'Unknown',
    country: countryMatch ? countryMatch[1].trim() : 'Unknown',
  };
}

// ── Parse ─────────────────────────────────────────────────────────────────

const releases = [];
const imgAltRegex = /<img[^>]+alt="([^"]*\s[-\u2013\u2014]\s[^"]+)"[^>]*>/gi;
let imgMatch;

while ((imgMatch = imgAltRegex.exec(html)) !== null) {
  const altText  = imgMatch[1];
  const imgStart = imgMatch.index;

  if (!altText.match(/\s[-\u2013\u2014]\s/)) continue;

  const chunk = html.slice(imgStart, imgStart + 2000);
  if (!/Genre:/i.test(chunk)) continue;

  const srcMatch = imgMatch[0].match(/(?:data-src|src)="([^"]+)"/i);
  const coverUrl = srcMatch ? srcMatch[1] : '';
  if (coverUrl.includes('no_image') || coverUrl.includes('coredark')) continue;

  const linkMatch = chunk.match(/<a\s+(?:[^>]*\s+)?href="([^"]+)"/i);
  const postUrl   = linkMatch ? linkMatch[1] : '';

  const plainText = chunk.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ');

  const { band, album, type, year } = parseTitle(altText);
  const { genre, genres, country, quality } = extractMeta(plainText);

  releases.push({
    json: {
      artist:    band,
      track:     album,
      type,
      year,
      genre,
      genres,
      country,
      imageUrl:  coverUrl,
      sourceUrl: postUrl || 'https://coreradio.online/',
      fullTitle: altText,
      scrapedAt: new Date().toISOString()
    }
  });
}

if (releases.length === 0) {
  return [{ json: {
    debug: true,
    htmlLength: html.length,
    htmlSnippet: html.slice(0, 1000),
    note: 'HTML received but no releases parsed — check htmlSnippet'
  }}];
}

return releases;

// Deduplicate: only pass through releases whose sourceUrl hasn't been seen before.
// Also persists new URLs back into workflow static data.

const store    = $getWorkflowStaticData('global');
const seenUrls = new Set(store.seenUrls || []);

const items  = $input.all();
const newOnes = [];

for (const item of items) {
  const url = item.json.sourceUrl;
  if (!seenUrls.has(url)) {
    seenUrls.add(url);
    newOnes.push(item);
  }
}

// Persist updated set (convert back to array for JSON storage)
store.seenUrls = Array.from(seenUrls);

// If nothing new, return a single sentinel so downstream nodes don't hang
if (newOnes.length === 0) {
  return [{ json: { noNewReleases: true } }];
}

return newOnes;

// Load favorites from shared static data (managed by the Bot Manager workflow)
const store = $getWorkflowStaticData('global');

const favBands  = store.favBands  || ['Vildhjarta', 'Allt', 'Imminence', 'Karmanjaka', "Humanity's Last Breath", 'Invent Animate', 'Currents', 'Lorna Shore', 'Spiritbox', 'Sleep Token', 'Bring Me The Horizon'];
const favGenres = store.favGenres || ['Djent', 'Progressive Metalcore', 'Thall', 'Progressive Metal', 'Deathcore', 'Post-Hardcore'];
const notGenres = store.notGenres || ['Acoustic', 'Classic Rock', 'Pop Metal', 'Nu Metal', 'Rap Metal'];

// Persist defaults if first time
if (!store.favBands)  store.favBands  = favBands;
if (!store.favGenres) store.favGenres = favGenres;
if (!store.notGenres) store.notGenres = notGenres;

const items = $input.all();
const releases = items.map((item, i) => ({
  id: i,
  artist:    item.json.artist,
  track:     item.json.track,
  genre:     item.json.genre,
  country:   item.json.country,
  year:      item.json.year,
  sourceUrl: item.json.sourceUrl,
  imageUrl:  item.json.imageUrl
}));

return [{ json: { releases, favBands, favGenres, notGenres } }];

// Parse Groq's JSON response and emit one item per relevant release
const raw = $input.first().json.text || '';

let relevant = [];
try {
  // Strip markdown fences if present
  const clean = raw.replace(/```json|```/g, '').trim();
  relevant = JSON.parse(clean);
} catch(e) {
  return [{ json: { error: 'Failed to parse Groq response', raw } }];
}

if (!Array.isArray(relevant) || relevant.length === 0) {
  return [{ json: { noRelevantReleases: true } }];
}

return relevant.map(r => ({ json: r }));

// Collect all items from all pages into one batch.
// If all items are sentinels (noNewReleases), emit a single sentinel.
// Otherwise emit a single item with all new releases combined.

const items = $input.all();
const newReleases = items.filter(item => !item.json.noNewReleases);

if (newReleases.length === 0) {
  return [{ json: { noNewReleases: true } }];
}

// Emit individual items (one per release) so Has New Releases? works correctly
return newReleases;

// Parse Groq's intent response and update static data accordingly
const raw = $input.first().json.text || '';

let intent;
try {
  const clean = raw.replace(/```json|```/g, '').trim();
  intent = JSON.parse(clean);
} catch(e) {
  return [{ json: { reply: "Sorry, I didn't understand that. Try: 'add band Spiritbox' or 'remove genre Nu Metal'" } }];
}

// NOTE: Static data here is scoped to THIS workflow.
// To share with the scraper, we use a workaround: store in a shared key
// by writing to n8n's global static data via the same key name.
const store = $getWorkflowStaticData('global');

// Load current lists with defaults
const favBands  = store.favBands  || ['Vildhjarta', 'Allt', 'Imminence', 'Karmanjaka', "Humanity's Last Breath", 'Invent Animate', 'Currents', 'Lorna Shore', 'Spiritbox', 'Sleep Token', 'Bring Me The Horizon'];
const favGenres = store.favGenres || ['Djent', 'Progressive Metalcore', 'Thall', 'Progressive Metal', 'Deathcore', 'Post-Hardcore'];
const notGenres = store.notGenres || ['Acoustic', 'Classic Rock', 'Pop Metal', 'Nu Metal', 'Rap Metal'];

const lists = { favBands, favGenres, notGenres };

let reply = intent.reply || 'Done!';

if (intent.action === 'add' && intent.listType && intent.value) {
  const list = lists[intent.listType];
  if (!list.map(x => x.toLowerCase()).includes(intent.value.toLowerCase())) {
    list.push(intent.value);
    store[intent.listType] = list;
  } else {
    reply = `"${intent.value}" is already in your ${intent.listType} list.`;
  }
}
else if (intent.action === 'remove' && intent.listType && intent.value) {
  const before = lists[intent.listType].length;
  lists[intent.listType] = lists[intent.listType].filter(
    x => x.toLowerCase() !== intent.value.toLowerCase()
  );
  store[intent.listType] = lists[intent.listType];
  if (lists[intent.listType].length === before) {
    reply = `"${intent.value}" was not found in your ${intent.listType} list.`;
  }
}
else if (intent.action === 'list') {
  reply = `🎸 *Favorite Bands:*\n${favBands.join(', ')}\n\n🎵 *Favorite Genres:*\n${favGenres.join(', ')}\n\n🚫 *Not Interested In:*\n${notGenres.join(', ')}`;
}
else if (intent.action === 'unknown') {
  reply = "I didn't get that. Try:\n• 'add band Sleep Token'\n• 'remove genre Nu Metal'\n• 'I don't like Rap Metal'\n• 'show my favorites'";
}

return [{ json: { reply, chatId: $input.all()[0]?.json?.message?.chat?.id } }];
